		regb = x__NewAST(tls, cc, int32(_AST_RANGEREF), (*_AST)(unsafe.Pointer((*_AST)(unsafe.Pointer(src)).Fleft)).Fright, (*_AST)(unsafe.Pointer(src)).Fright)
